/**
 * Tests for getCachedBranch()'s subprocess-free HEAD parsing (#2948).
 *
 * The old implementation spawned `git branch --show-current` synchronously
 * (5s timeout) on every fresh hook process. Under fork pressure and
 * index.lock contention from concurrent sessions that spawn ran for
 * seconds, blowing the hook's own timeout. The replacement parses
 * `.git/HEAD` directly, so these tests build real on-disk layouts — no
 * git binary involved anywhere.
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { getCachedBranch } from '../../lib/env.js';

let dir: string;

function layoutRegularRepo(branch: string): void {
  mkdirSync(join(dir, '.git'), { recursive: true });
  writeFileSync(join(dir, '.git', 'HEAD'), `ref: refs/heads/${branch}\n`);
}

describe('getCachedBranch — .git/HEAD parsing (#2948)', () => {
  beforeEach(() => {
    dir = mkdtempSync(join(tmpdir(), 'ork-branch-'));
  });
  afterEach(() => {
    rmSync(dir, { recursive: true, force: true });
  });

  it('reads the branch from a regular repo HEAD symref', () => {
    layoutRegularRepo('feat/some-branch');
    expect(getCachedBranch(dir)).toBe('feat/some-branch');
  });

  it('handles branch names containing slashes and dots', () => {
    layoutRegularRepo('release/v8.77.1');
    expect(getCachedBranch(dir)).toBe('release/v8.77.1');
  });

  it('follows a linked-worktree .git POINTER FILE to its gitdir', () => {
    // Worktree layout: <dir>/.git is a FILE containing "gitdir: <path>".
    const gitdir = join(dir, 'main-repo', '.git', 'worktrees', 'wt1');
    mkdirSync(gitdir, { recursive: true });
    writeFileSync(join(gitdir, 'HEAD'), 'ref: refs/heads/fix/wt-branch\n');
    const wt = join(dir, 'wt');
    mkdirSync(wt);
    writeFileSync(join(wt, '.git'), `gitdir: ${gitdir}\n`);
    expect(getCachedBranch(wt)).toBe('fix/wt-branch');
  });

  it('returns empty string on detached HEAD (same as --show-current)', () => {
    mkdirSync(join(dir, '.git'), { recursive: true });
    writeFileSync(join(dir, '.git', 'HEAD'), 'a1b2c3d4e5f60718293a4b5c6d7e8f9012345678\n');
    expect(getCachedBranch(dir)).toBe('');
  });

  it('returns "unknown" when there is no .git at all', () => {
    expect(getCachedBranch(dir)).toBe('unknown');
  });

  it('returns "unknown" on a malformed .git pointer file', () => {
    writeFileSync(join(dir, '.git'), 'this is not a gitdir pointer\n');
    expect(getCachedBranch(dir)).toBe('unknown');
  });

  it('caches per directory: second call survives HEAD deletion', () => {
    layoutRegularRepo('feat/cached');
    expect(getCachedBranch(dir)).toBe('feat/cached');
    rmSync(join(dir, '.git'), { recursive: true, force: true });
    expect(getCachedBranch(dir)).toBe('feat/cached');
  });
});

/**
 * The cycle-prevention argument for #2970 rests entirely on git-head.ts being
 * a LEAF. env.ts already imports session-id-generator.ts, so if the shared
 * branch helper ever grows a local import it can close a loop and produce
 * undefined-at-import-time in the esbuild bundle. Encode the invariant rather
 * than trusting a comment someone has to notice.
 */
describe('git-head.ts is a leaf module (#2970)', () => {
  const readSrc = async (rel: string): Promise<string> => {
    const { readFileSync: realRead } =
      await vi.importActual<typeof import('node:fs')>('node:fs');
    return realRead(new URL(rel, import.meta.url), 'utf8') as string;
  };

  it('imports nothing from lib/ — only node: builtins', async () => {
    const src = await readSrc('../../lib/git-head.ts');
    const imports = [...src.matchAll(/^import .*? from '([^']+)';$/gm)].map((m) => m[1]);

    expect(imports.length).toBeGreaterThan(0);
    for (const spec of imports) {
      expect(spec).toMatch(/^node:/);
    }
  });

  // Asserted on the IMPORT, not on the bare word: this file's own docstring
  // names the `execFileSync` call it replaced, and a raw substring match would
  // flag that prose. (Precisely the comment-matching false positive that made
  // hq-ext's silent-failure gate unusable.)
  it('spawns no subprocess', async () => {
    const src = await readSrc('../../lib/git-head.ts');
    const imports = [...src.matchAll(/^import .*? from '([^']+)';$/gm)].map((m) => m[1]);
    expect(imports).not.toContain('node:child_process');
  });
});
